parameters.jsCode:
const input = $('Webhook').first().json.body;

const employeeName = input['Full Legal Name'];
const managerName = input['Manager Name'];
const startDate = input['Start Date'];
const department = input['Department'];
const managerEmail = input['Manager Email'];
const employeeEmail = input['Personal Email Address'];
const jobTitle = input['Job Title'];
const orientationTime = input['Orientation Time'];
const phone = String(input['Phone Number']);
const dob = input['Date of Birth'];
const offerLetter = input['Please upload a copy of your signed offer letter or contract'];

let tasks = [
  { task: 'Schedule 1:1 Intro Meeting', priority: 'High', daysAfter: 0 },
  { task: 'Prepare Workstation Access', priority: 'High', daysAfter: 0 },
  { task: 'Add to Team Slack Channels', priority: 'Medium', daysAfter: 0 },
  { task: 'Share Team Documentation', priority: 'Medium', daysAfter: 1 },
  { task: 'Complete HR Paperwork', priority: 'High', daysAfter: 2 },
];

if (department === 'Engineering') {
  tasks.push({ task: 'Setup GitHub Access', priority: 'High', daysAfter: 0 });
  tasks.push({ task: 'Setup Dev Environment', priority: 'High', daysAfter: 1 });
  tasks.push({ task: 'Code Review Guidelines Shared', priority: 'Medium', daysAfter: 2 });
} else if (department === 'Product') {
  tasks.push({ task: 'Setup Product Management Tools', priority: 'High', daysAfter: 0 });
  tasks.push({ task: 'Share Product Roadmap', priority: 'High', daysAfter: 1 });
  tasks.push({ task: 'Intro to Active Sprints', priority: 'Medium', daysAfter: 2 });
} else if (department === 'Design') {
  tasks.push({ task: 'Setup Figma Access', priority: 'High', daysAfter: 0 });
  tasks.push({ task: 'Share Design System', priority: 'High', daysAfter: 1 });
  tasks.push({ task: 'Intro to Brand Guidelines', priority: 'Medium', daysAfter: 2 });
} else if (department === 'Operations') {
  tasks.push({ task: 'Setup Operations Tools Access', priority: 'High', daysAfter: 0 });
  tasks.push({ task: 'Share SOPs Documentation', priority: 'High', daysAfter: 1 });
  tasks.push({ task: 'Assign Operations Workflows', priority: 'Medium', daysAfter: 2 });
} else if (department === 'Marketing') {
  tasks.push({ task: 'Setup Marketing Tools Access', priority: 'High', daysAfter: 0 });
  tasks.push({ task: 'Share Brand Guidelines', priority: 'High', daysAfter: 1 });
  tasks.push({ task: 'Intro to Active Campaigns', priority: 'Medium', daysAfter: 2 });
} else if (department === 'Sales') {
  tasks.push({ task: 'Setup CRM Access', priority: 'High', daysAfter: 0 });
  tasks.push({ task: 'Share Sales Playbook', priority: 'High', daysAfter: 1 });
  tasks.push({ task: 'Assign Sales Territory', priority: 'Medium', daysAfter: 2 });
}

return tasks.map(item => ({
  json: {
    ...item,
    employeeName,
    managerName,
    startDate,
    department,
    managerEmail,
    employeeEmail,
    jobTitle,
    orientationTime,
    phone,
    dob,
    offerLetter
  },
  pairedItem: { item: 0 }
}));

parameters.text:
=Write a warm professional welcome email for a new employee.

Employee Details:
- Name: {{ $('Webhook').first().json.body['Full Legal Name'] }}
- Job Title: {{ $('Webhook').first().json.body['Job Title'] }}
- Department: {{ $('Webhook').first().json.body['Department'] }}
- Start Date: {{ $('Webhook').first().json.body['Start Date'] }}
- Orientation Time: {{ $('Webhook').first().json.body['Orientation Time'] }}
- Manager: {{ $('Webhook').first().json.body['Manager Name'] }}

Email must include:
1. Warm welcome greeting
2. Excitement about joining
3. Orientation scheduled on Start Date at Orientation Time
